LANG_DATA['tsg'].meta = { family:'Austronesian (Greater Central Philippine)', speakers:'~1.1M', countries:'Philippines (Sulu), Malaysia (Sabah)', official:'No (regional)', script:'Latin / Jawi (historical)', description:'Tausug (Bahasa Sūg) is the language of the Tausug people of the Sulu Archipelago. They were the dominant power of the precolonial Sultanate of Sulu, which ruled parts of present-day Philippines, Malaysia, and Indonesia.' };
