LANG_DATA['gbm'].meta = { family:'Indo-Aryan (Central Pahari)', speakers:'~2.5M', countries:'India (Uttarakhand)', official:'No (regional)', script:'Devanagari', description:'Garhwali is one of two principal Pahari languages of Uttarakhand state (with Kumaoni). It descends from Khasa Prakrit and preserves several archaic Indo-Aryan features. Recognized as an "Other Hindi" tongue rather than a separate scheduled language.' };
LANG_DATA['kfy'].meta = { family:'Indo-Aryan (Central Pahari)', speakers:'~2M', countries:'India (Uttarakhand)', official:'No (regional)', script:'Devanagari', description:'Kumaoni is the principal language of the Kumaon region of Uttarakhand, paired with Garhwali in the Central Pahari group. It has a rich folk literature and modern Kumaoni-medium media including newspapers and radio.' };
