LANG_DATA['umb'].meta = { family:'Niger-Congo (Bantu, R10)', speakers:'~6M', countries:'Angola', official:'Angola (national)', script:'Latin', description:'Umbundu is the largest indigenous language of Angola, native to the central plateau (Bie province). It serves as a major regional lingua franca and was an important language of trade with the Portuguese empire.' };
