LANG_DATA['xal'].meta = { family:'Mongolic (Western/Oirat)', speakers:'~80K', countries:'Russia (Kalmykia)', official:'Republic of Kalmykia', script:'Cyrillic / Clear Script (1648, historical)', description:'Kalmyk is the European Mongolic language, descended from 17th-c. Oirat migrations to the lower Volga. The Clear Script (Todo bichig) was created in 1648 by Zaya Pandita; modern Kalmyk uses Cyrillic with extra letters һ, ң, ө, ү.' };
LANG_DATA['sg'].meta = { family:'Niger-Congo (Adamawa-Ubangian)', speakers:'~5M (lingua franca, ~500K L1)', countries:'Central African Republic', official:'CAR (with French)', script:'Latin', description:'Sango (Sängö) is the lingua franca of the Central African Republic, originating as a trade pidgin based on Northern Ngbandi during 19th-c. river commerce. It is one of the few African languages to function as both an official language and a creole-like lingua franca.' };
