// === Phase 4: Historical / Ancient Languages metadata ===
LANG_DATA['peo'].meta = { family:'Indo-European (Iranian, Old)', speakers:'Extinct (~550-330 BCE)', countries:'Achaemenid Persia (modern Iran/Iraq)', official:'Achaemenid Empire', script:'Old Persian cuneiform', description:'Old Persian was the language of the Achaemenid Empire (c. 550-330 BCE), preserved in the trilingual royal inscriptions at Behistun and elsewhere. Its unique cuneiform syllabary, derived from but distinct from Akkadian cuneiform, was used almost exclusively for royal monumental inscriptions. It is the direct ancestor of Middle Persian and ultimately Modern Persian.' };
LANG_DATA['ave'].meta = { family:'Indo-European (Iranian, Old)', speakers:'Extinct as L1; liturgical use in Zoroastrianism', countries:'Eastern Iran / Central Asia (origin)', official:'No (sacred liturgical)', script:'Avestan alphabet (Sasanian period)', description:'Avestan is the sacred language of Zoroastrianism, preserved in the Avesta scriptures. Two stages exist: Old Avestan (the Gathas attributed to Zarathushtra, c. 1500-1000 BCE) and Younger Avestan (c. 700-300 BCE). The Avestan alphabet was developed in the Sasanian period to record orally transmitted liturgy.' };
LANG_DATA['xto'].meta = { family:'Indo-European (Tocharian)', speakers:'Extinct (5th-10th c. CE)', countries:'Tarim Basin (modern Xinjiang, China)', official:'No', script:'Brahmi-derived Tocharian script', description:'Tocharian A (Eastern Tocharian, sometimes called Agnean) is one of two extinct Indo-European languages of the Tarim Basin oases. Attested in Buddhist manuscripts, its discovery in the early 20th century revealed that Indo-European had reached the easternmost edge of Eurasia. It survives only in religious texts; Tocharian B has a wider corpus.' };
LANG_DATA['txb'].meta = { family:'Indo-European (Tocharian)', speakers:'Extinct (5th-10th c. CE)', countries:'Tarim Basin (modern Xinjiang)', official:'No', script:'Brahmi-derived Tocharian script', description:'Tocharian B (Western Tocharian, Kuchean) is the more widely attested Tocharian language, with both religious and secular documents from the Buddhist kingdom of Kucha. Both Tocharian languages went extinct by 1000 CE as Turkic peoples (Uyghurs) replaced them in the region.' };
LANG_DATA['phn'].meta = { family:'Afro-Asiatic (Northwest Semitic, Canaanite)', speakers:'Extinct (~1500 BCE-3rd c. CE)', countries:'Phoenicia (Lebanon, coastal Syria/Israel) + Mediterranean colonies', official:'Phoenician city-states (Tyre, Sidon, Byblos, Carthage)', script:'Phoenician alphabet (𐤀𐤁𐤂)', description:'Phoenician was the Northwest Semitic language of the Phoenician city-states from c. 1500 BCE. The 22-letter Phoenician alphabet is the direct or indirect ancestor of nearly all modern alphabets — Greek, Latin, Cyrillic, Hebrew, Aramaic, Arabic, and South Asian Brahmic scripts. Punic was its late variant in Carthage.' };
LANG_DATA['uga'].meta = { family:'Afro-Asiatic (Northwest Semitic)', speakers:'Extinct (~1400-1180 BCE)', countries:'Ugarit (Bronze Age coastal Syria)', official:'Kingdom of Ugarit', script:'Ugaritic alphabetic cuneiform (30 signs)', description:'Ugaritic was a Northwest Semitic language at the Bronze Age city of Ugarit (modern Ras Shamra, Syria), c. 14th-12th centuries BCE. Its cuneiform alphabet of 30 signs is the earliest documented true alphabet (preceding Phoenician), and the Ugaritic mythological texts (Baal Cycle) provide essential cultural context for understanding the Hebrew Bible.' };
LANG_DATA['xlu'].meta = { family:'Indo-European (Anatolian)', speakers:'Extinct (~2000-700 BCE)', countries:'Anatolia (modern Turkey)', official:'Hittite Empire (co-language)', script:'Cuneiform (Bronze Age) / Anatolian hieroglyphs (Iron Age)', description:'Luwian was an Anatolian language closely related to Hittite, with two attestation traditions: cuneiform Luwian on Bronze Age clay tablets from Hattusa, and hieroglyphic Luwian on Iron Age stone monuments using the iconic Anatolian hieroglyphs. After the fall of Hattusa (~1180 BCE), Luwian outlived Hittite by several centuries.' };
LANG_DATA['pal'].meta = { family:'Indo-European (Iranian, Middle)', speakers:'Extinct as L1; Zoroastrian liturgical', countries:'Sasanian Empire (Iran, Iraq, parts of Central Asia)', official:'Sasanian Empire (224-651 CE)', script:'Pahlavi script (Inscriptional and Book varieties)', description:'Middle Persian (Pahlavi) was the official language of the Sasanian Empire and the bridge between Old Persian and Modern Persian. After the Arab conquest, it remained the liturgical and scholarly language of Zoroastrian communities. The Pahlavi script is a logographic-and-Aramaic-derived system notoriously difficult to read.' };
LANG_DATA['syc'].meta = { family:'Afro-Asiatic (Semitic, Aramaic, Eastern)', speakers:'Liturgical (~10K active liturgical use)', countries:'Originally Edessa (modern Şanlıurfa, Turkey)', official:'Eastern Christian liturgical language', script:'Syriac (Estrangela / Serto / Madnhāyā)', description:'Classical Syriac is a literary Aramaic language that flourished as the lingua franca of Eastern Christianity from the 2nd-13th centuries CE, centered on Edessa. It produced one of antiquity\'s greatest theological, philosophical, and scientific corpora, and remains the liturgical language of the Syriac Orthodox Church, Assyrian Church of the East, and others.' };
LANG_DATA['fro'].meta = { family:'Indo-European (Romance, Gallo-Romance)', speakers:'Extinct (~800-1340 CE)', countries:'Northern France', official:'Capetian France (selectively)', script:'Latin', description:'Old French (françois, romanz) is the form of French from c. 800-1340 CE in northern France. It is the language of the Chanson de Roland, the Roman de la Rose, Marie de France\'s Lais, and Chrétien de Troyes\'s Arthurian romances. It preserved a two-case system (subject/oblique) lost in Middle French.' };
LANG_DATA['goh'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~750-1050 CE)', countries:'Germany, Austria, Switzerland (Alemannic, Bavarian, Franconian)', official:'Frankish Empire (selectively)', script:'Latin', description:'Old High German is the earliest stage of High German (c. 750-1050 CE), distinguished from neighboring West Germanic languages by the High German consonant shift (e.g., t → z/ts, p → pf/f, k → ch). Major literary texts include the Lay of Hildebrand (Hildebrandslied) and Otfrid of Weissenburg\'s Evangelienbuch.' };
LANG_DATA['gez'].meta = { family:'Afro-Asiatic (Semitic, South, Ethiopic)', speakers:'Liturgical (no L1); Ethiopian/Eritrean Orthodox liturgy', countries:'Originally Aksum (modern northern Ethiopia/Eritrea)', official:'Ethiopian/Eritrean Orthodox Tewahedo Churches', script:'Ge\'ez script (Ethiopic abugida) ግዕዝ', description:'Ge\'ez (Classical Ethiopic) is a South Semitic language that served as the literary and royal language of the Ethiopian Empire from c. 4th century CE. It is the parent of Tigrinya, Tigre, and Amharic. The Ge\'ez script is still actively used for those three modern languages, and Ge\'ez itself remains the liturgical language of the Ethiopian and Eritrean Orthodox Tewahedo Churches.' };

// === Phase 4B: more Historical / Ancient Languages metadata ===
LANG_DATA['gmy'].meta = { family:'Indo-European (Hellenic, pre-classical)', speakers:'Extinct (~1450-1200 BCE)', countries:'Mycenaean Greece (Aegean)', official:'Bronze Age palace administrations', script:'Linear B syllabary (~90 syllabic + 100+ ideograms)', description:'Mycenaean Greek is the earliest attested form of Greek, recorded in the Linear B syllabary on Bronze Age clay tablets at Knossos, Pylos, Mycenae, and other palace sites. Its decipherment by Michael Ventris in 1952 proved that Greek-speakers were already in Greece in the Bronze Age. Vocabulary attested in Linear B is mostly administrative; many basic words must be reconstructed via Classical Greek.' };
LANG_DATA['xct'].meta = { family:'Sino-Tibetan (Tibeto-Burman, Bodish)', speakers:'Liturgical (Tibetan Buddhism)', countries:'Tibet (originally), China, Mongolia, India, Bhutan, Nepal', official:'Tibetan Buddhist liturgical language', script:'Tibetan (Uchen) ྑ', description:'Classical Tibetan refers to the literary form of Tibetan from c. 7th-12th centuries CE, used for the translation of the Buddhist canon (Kangyur and Tengyur) and indigenous Tibetan literature. Its orthography preserves features of Old Tibetan that have been radically altered in modern spoken Tibetan. It remains the liturgical language of Tibetan Buddhism.' };
LANG_DATA['xpu'].meta = { family:'Afro-Asiatic (Northwest Semitic, Canaanite)', speakers:'Extinct (~800 BCE-5th c. CE)', countries:'Carthage and the Punic Mediterranean (Tunisia, Sardinia, Sicily, Malta, etc.)', official:'Carthaginian Empire', script:'Punic alphabet (cursive Phoenician)', description:'Punic was the late variety of Phoenician spoken across the Carthaginian commercial empire and its successor states. After Roman conquest, it persisted as a regional language in North Africa for centuries, with Augustine of Hippo (5th c. CE) attesting to ongoing Punic usage. Neo-Punic developed cursive script forms.' };
LANG_DATA['xhu'].meta = { family:'Hurro-Urartian (separate from IE/Semitic)', speakers:'Extinct (~2300-1000 BCE)', countries:'Mitanni and northern Mesopotamia (modern N Iraq, Syria, SE Turkey)', official:'Mitanni kingdom', script:'Cuneiform', description:'Hurrian was a major Near Eastern language of the 3rd-2nd millennia BCE, used as the lingua franca of the Mitanni kingdom and known from cuneiform tablets at Yorgan Tepe (Nuzi), Bogazköy, and elsewhere. Together with Urartian (a sister language), it forms the Hurro-Urartian family, with no proven relations to other languages — possibly a Caucasian connection has been proposed.' };
LANG_DATA['elx'].meta = { family:'Language isolate (Elamite)', speakers:'Extinct (~2700-300 BCE)', countries:'Elam (modern southwestern Iran)', official:'Elamite Empire, Achaemenid administration', script:'Elamite cuneiform / Linear Elamite (undeciphered earlier form)', description:'Elamite is a poorly classified language of ancient southwestern Iran, attested for over 2,000 years. The Achaemenid Persians used Elamite as one of their three administrative languages (alongside Old Persian and Akkadian). The earlier Linear Elamite script was largely undeciphered until partial readings were proposed in 2020.' };
LANG_DATA['xsa'].meta = { family:'Afro-Asiatic (Semitic, South, Old South Arabian)', speakers:'Extinct (~1000 BCE-600 CE)', countries:'Sabaean kingdom (modern Yemen, southwestern Arabia)', official:'Sabaean and Himyarite kingdoms', script:'Old South Arabian script (Musnad, 𐩠𐩡𐩢𐩣)', description:'Sabaean is the most-attested Old South Arabian language, used in tens of thousands of inscriptions across ancient Yemen, especially around the Marib dam. The Musnad script (also called Old South Arabian) is the ancestor of Ge\'ez script, transmitted via early Aksumite contact across the Red Sea.' };
LANG_DATA['kaw'].meta = { family:'Austronesian (Malayo-Polynesian, Javanic)', speakers:'Extinct as L1; literary (Hindu-Buddhist scholarly use in Bali)', countries:'Java, Bali (Hindu-Buddhist period)', official:'Javanese Hindu-Buddhist kingdoms (Mataram, Majapahit)', script:'Kawi script (ancestor of Balinese, Javanese, Lontara)', description:'Old Javanese (Kawi) is the form of Javanese used in literary and religious texts from the 9th to 15th centuries CE. It is heavily influenced by Sanskrit, with much philosophical, religious, and learned vocabulary borrowed directly. The Kawi script (Hanacaraka ancestor) is the source of all later Indonesian Brahmic scripts. Kawi continues in ceremonial use in Bali.' };
LANG_DATA['kho'].meta = { family:'Indo-European (Iranian, Saka)', speakers:'Extinct (~5th-10th c. CE)', countries:'Khotan (Tarim Basin, modern Xinjiang)', official:'Buddhist kingdom of Khotan', script:'Brahmi-derived Khotanese script', description:'Khotanese (also called Khotanese Saka) is a Middle Iranian language of the eastern Saka group, attested in Buddhist manuscripts from the kingdom of Khotan on the southern Silk Road. It is closely related to Tumshuqese (also Saka) and more distantly to Sogdian and other Eastern Iranian languages. Like Tocharian, it disappeared as Turkic peoples occupied the Tarim Basin.' };
LANG_DATA['gmh'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~1050-1350 CE)', countries:'Germany, Austria, Switzerland (medieval)', official:'Holy Roman Empire (selectively)', script:'Latin', description:'Middle High German is the form of High German between Old High German and Early New High German. It is the language of the Nibelungenlied, the Minnesänger (especially Walter von der Vogelweide), Wolfram von Eschenbach\'s Parzival, and Gottfried von Strassburg\'s Tristan. The High German consonant shift was complete by the Middle High German period.' };
LANG_DATA['osp'].meta = { family:'Indo-European (Romance, Iberian)', speakers:'Extinct (~10th c. - early 16th c.)', countries:'Castile, León, Spain (medieval)', official:'Kingdom of Castile (selectively)', script:'Latin', description:'Old Spanish (Castilian) is the form of Spanish from c. 1000 to early 1500s, characterized by complex sibilant systems (𐌽 ts/dz, š/ž, s/z) that simplified into Modern Spanish during the early modern period. Major works include the Cantar de Mio Cid (12th c.), Alfonso X\'s legal and scientific texts, and the Libro de buen amor of Juan Ruiz.' };
LANG_DATA['okz'].meta = { family:'Austroasiatic (Mon-Khmer)', speakers:'Extinct (~7th-15th c. CE)', countries:'Khmer Empire (modern Cambodia, Thailand, Laos, Vietnam)', official:'Khmer Empire (Angkor)', script:'Old Khmer script (ancestor of modern Khmer script)', description:'Old Khmer is the form of Khmer attested in inscriptions from the 7th-15th centuries CE, especially during the Khmer Empire centered on Angkor. Inscriptions on stone temples document royal grants, religious foundations, and administrative matters. The Old Khmer script is a direct ancestor of modern Khmer script and was a major influence on Thai and Lao scripts.' };
LANG_DATA['osx'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~750-1100 CE)', countries:'Westphalia, Lower Saxony (modern northern Germany)', official:'Saxon territories (selectively)', script:'Latin', description:'Old Saxon (Old Low German) is the earliest documented form of Low German, distinguished from Old High German by lacking the High German consonant shift. The most important Old Saxon text is the Heliand (c. 830 CE), a 6,000-line alliterative epic retelling of the Gospel narrative — one of the longest poems in any early Germanic language.' };

