LANG_DATA['yag'].meta = { family:'Indo-European (Iranian, Eastern)', speakers:'~13K', countries:'Tajikistan (Yaghnob Valley)', official:'No (recognized minority)', script:'Cyrillic / Latin', description:'Yaghnobi is the only modern descendant of Sogdian, the Eastern Iranian lingua franca of the Silk Road for over 1,000 years. Spoken by descendants of Sogdian refugees who fled to the inaccessible Yaghnob Valley after the 8th-century Arab conquest. It is one of the most linguistically significant minority languages in the world.' };
