LANG_DATA['kwk'].meta = { family:'Wakashan (Northern)', speakers:'~250 (severely endangered)', countries:'Canada (British Columbia coast)', official:'No (recognized aboriginal)', script:'Latin (with apostrophes for ejectives, x̱ for /x/, ƛ for /tɬ/)', description:'Kwak\'wala is the principal Northern Wakashan language, spoken by the Kwakwaka\'wakw of British Columbia\'s central coast. It has an extraordinarily complex consonant inventory with ejectives (k\', t\'), uvulars, lateral affricates, and contrasting series. Famous for the elaborate potlatch ceremonies of its speakers.' };
LANG_DATA['sad'].meta = { family:'Khoisan (proposed isolate or with Hadza)', speakers:'~60K', countries:'Tanzania (Kondoa District)', official:'No (recognized minority)', script:'Latin (with click letters ǀ ǁ ǂ ǃ)', description:'Sandawe is a click language of central Tanzania, sometimes proposed to be related to the Khoekhoe family or grouped with Hadza, but generally considered an isolate. It has 4 phonemic click types and a 5-tone system, making it one of Africa\'s most phonologically complex languages.' };
LANG_DATA['pcc'].meta = { family:'Kra-Dai (Tai, Northern)', speakers:'~3M', countries:'China (Guizhou, Yunnan)', official:'No (recognized minority)', script:'Latin (Buyei) / Chinese characters / Old Bouyei script', description:'Bouyei (Buyei) is closely related to Northern Zhuang, with which it forms a dialect continuum. The Romanized Bouyei orthography uses tone letters (l, x, z, q, h, j) at syllable end to mark its 6-8 tones. It has a long literary tradition using Chinese-character-based scripts for ritual texts.' };
