LANG_DATA['hui'].meta = { family:'Trans-New Guinea (Engan)', speakers:'~150K', countries:'Papua New Guinea (Hela Province)', official:'No (recognized regional)', script:'Latin', description:'Huli is one of the largest Engan languages of the New Guinea highlands. Huli speakers are known for their elaborate wig traditions and the famous Huli Wigmen culture. It uses a base-15 numeral system, unusual among the world\'s languages.' };
