LANG_DATA['squ'].meta = { family:'Salishan (Coast Salish, Central)', speakers:'~10 fluent (severely endangered)', countries:'Canada (British Columbia coast around Squamish)', official:'No (recognized aboriginal)', script:'Latin (with diacritics, apostrophes for ejectives, ƛ for /tɬ/)', description:'Squamish (Sḵwx̱wú7mesh sníchim) is a Salishan language with extreme phonological complexity — voiceless lateral affricates, ejectives, uvulars, pharyngeals, and a distinctive pharyngeal stop /ʕ̚/. The community runs immersion programs and Squamish-medium schools to revitalize the language.' };
