LANG_DATA['hbo'].meta = { family:'Afro-Asiatic (Semitic, Northwest, Canaanite)', speakers:'Liturgical (revived as Modern Hebrew in 19th c.)', countries:'Ancient Israel/Judah (Levant)', official:'Ancient Israelite kingdoms; Jewish liturgy', script:'Paleo-Hebrew (early) → Hebrew (square script, post-exilic)', description:'Biblical Hebrew is the form of Hebrew used in the Hebrew Bible (Tanakh), c. 1200-200 BCE. It has 7 vowel phonemes (with phonemic length distinctions in older stages), pharyngeals, ejectives or emphatics, and a verb system based on root-and-pattern morphology. Modern Hebrew was revived from Biblical Hebrew in the 19th century.' };

